// LocalDataManager.js
import AsyncStorage from '@react-native-async-storage/async-storage';
import * as SecureStore from 'expo-secure-store';

// Storage Keys
const KEYS = {
  // AsyncStorage keys (non-sensitive)
  USER_PREFERENCES: '@app/user_preferences',
  APP_SETTINGS: '@app/app_settings',
  PROFILE_INFO: '@app/profile_info',
  SESSION_DATA: '@app/session_data',
  OFFLINE_CONTENT: '@app/offline_content',
  CACHE_METADATA: '@app/cache_metadata',
  THEME_SETTINGS: '@app/theme_settings',
  LANGUAGE: '@app/language',
  ONBOARDING_COMPLETE: '@app/onboarding_complete',
  LAST_SYNC_TIMESTAMP: '@app/last_sync_timestamp',

  // SecureStore keys (sensitive)
  SECURE_AUTH_TOKEN: 'secure_auth_token',
  SECURE_REFRESH_TOKEN: 'secure_refresh_token',
  SECURE_USER_ID: 'secure_user_id',
  SECURE_SESSION_SECRET: 'secure_session_secret',
};

// Default TTL for cached content (24 hours in ms)
const DEFAULT_CACHE_TTL = 24 * 60 * 60 * 1000;

// In-memory cache for frequently accessed data
const memoryCache = new Map();

// ============================================================
// Secure Storage (for sensitive data like tokens)
// ============================================================
const SecureStorage = {
  async set(key, value) {
    try {
      const stringValue = typeof value === 'string' ? value : JSON.stringify(value);
      await SecureStore.setItemAsync(key, stringValue);
      return true;
    } catch (error) {
      console.error(`SecureStorage.set error for key "${key}":`, error);
      return false;
    }
  },

  async get(key) {
    try {
      const value = await SecureStore.getItemAsync(key);
      if (value === null) return null;
      try {
        return JSON.parse(value);
      } catch {
        return value;
      }
    } catch (error) {
      console.error(`SecureStorage.get error for key "${key}":`, error);
      return null;
    }
  },

  async remove(key) {
    try {
      await SecureStore.deleteItemAsync(key);
      return true;
    } catch (error) {
      console.error(`SecureStorage.remove error for key "${key}":`, error);
      return false;
    }
  },

  async clearAll() {
    const secureKeys = [
      KEYS.SECURE_AUTH_TOKEN,
      KEYS.SECURE_REFRESH_TOKEN,
      KEYS.SECURE_USER_ID,
      KEYS.SECURE_SESSION_SECRET,
    ];
    const results = await Promise.allSettled(
      secureKeys.map((key) => SecureStore.deleteItemAsync(key))
    );
    return results.every((r) => r.status === 'fulfilled');
  },
};

// ============================================================
// Cache Storage (AsyncStorage with TTL and memory cache)
// ============================================================
const CacheStorage = {
  async set(key, value, ttl = DEFAULT_CACHE_TTL) {
    try {
      const cacheEntry = {
        data: value,
        timestamp: Date.now(),
        ttl,
      };
      const stringValue = JSON.stringify(cacheEntry);
      await AsyncStorage.setItem(key, stringValue);
      memoryCache.set(key, cacheEntry);
      return true;
    } catch (error) {
      console.error(`CacheStorage.set error for key "${key}":`, error);
      return false;
    }
  },

  async get(key, ignoreExpiry = false) {
    try {
      // Check memory cache first
      if (memoryCache.has(key)) {
        const cached = memoryCache.get(key);
        if (ignoreExpiry || !this._isExpired(cached)) {
          return cached.data;
        }
        memoryCache.delete(key);
      }

      const stringValue = await AsyncStorage.getItem(key);
      if (stringValue === null) return null;

      const cacheEntry = JSON.parse(stringValue);

      if (!ignoreExpiry && this._isExpired(cacheEntry)) {
        await AsyncStorage.removeItem(key);
        return null;
      }

      memoryCache.set(key, cacheEntry);
      return cacheEntry.data;
    } catch (error) {
      console.error(`CacheStorage.get error for key "${key}":`, error);
      return null;
    }
  },

  async remove(key) {
    try {
      memoryCache.delete(key);
      await AsyncStorage.removeItem(key);
      return true;
    } catch (error) {
      console.error(`CacheStorage.remove error for key "${key}":`, error);
      return false;
    }
  },

  async multiGet(keys) {
    try {
      const results = {};
      const missingKeys = [];

      // Check memory cache first
      for (const key of keys) {
        if (memoryCache.has(key)) {
          const cached = memoryCache.get(key);
          if (!this._isExpired(cached)) {
            results[key] = cached.data;
          } else {
            memoryCache.delete(key);
            missingKeys.push(key);
          }
        } else {
          missingKeys.push(key);
        }
      }

      if (missingKeys.length > 0) {
        const pairs = await AsyncStorage.multiGet(missingKeys);
        for (const [key, stringValue] of pairs) {
          if (stringValue !== null) {
            const cacheEntry = JSON.parse(stringValue);
            if (!this._isExpired(cacheEntry)) {
              results[key] = cacheEntry.data;
              memoryCache.set(key, cacheEntry);
            }
          }
        }
      }

      return results;
    } catch (error) {
      console.error('CacheStorage.multiGet error:', error);
      return {};
    }
  },

  async clearAll() {
    try {
      const allKeys = await AsyncStorage.getAllKeys();
      const appKeys = allKeys.filter((key) => key.startsWith('@app/'));
      if (appKeys.length > 0) {
        await AsyncStorage.multiRemove(appKeys);
      }
      memoryCache.clear();
      return true;
    } catch (error) {
      console.error('CacheStorage.clearAll error:', error);
      return false;
    }
  },

  _isExpired(cacheEntry) {
    if (!cacheEntry || !cacheEntry.timestamp || !cacheEntry.ttl) return true;
    if (cacheEntry.ttl === -1) return false; // Never expires
    return Date.now() - cacheEntry.timestamp > cacheEntry.ttl;
  },
};

// ============================================================
// Token Manager (uses SecureStorage)
// ============================================================
const TokenManager = {
  async saveTokens({ authToken, refreshToken }) {
    const results = await Promise.allSettled([
      authToken ? SecureStorage.set(KEYS.SECURE_AUTH_TOKEN, authToken) : Promise.resolve(),
      refreshToken ? SecureStorage.set(KEYS.SECURE_REFRESH_TOKEN, refreshToken) : Promise.resolve(),
    ]);
    return results.every((r) => r.status === 'fulfilled');
  },

  async getAuthToken() {
    return SecureStorage.get(KEYS.SECURE_AUTH_TOKEN);
  },

  async getRefreshToken() {
    return SecureStorage.get(KEYS.SECURE_REFRESH_TOKEN);
  },

  async getTokens() {
    const [authToken, refreshToken] = await Promise.all([
      SecureStorage.get(KEYS.SECURE_AUTH_TOKEN),
      SecureStorage.get(KEYS.SECURE_REFRESH_TOKEN),
    ]);
    return { authToken, refreshToken };
  },

  async clearTokens() {
    await Promise.allSettled([
      SecureStorage.remove(KEYS.SECURE_AUTH_TOKEN),
      SecureStorage.remove(KEYS.SECURE_REFRESH_TOKEN),
      SecureStorage.remove(KEYS.SECURE_SESSION_SECRET),
    ]);
    return true;
  },

  async isAuthenticated() {
    const token = await this.getAuthToken();
    return token !== null;
  },
};

// ============================================================
// Profile Manager (non-sensitive profile data in AsyncStorage,
// user ID in SecureStore)
// ============================================================
const ProfileManager = {
  async saveProfile(profileData) {
    // Store user ID securely, everything else in AsyncStorage
    const { userId, ...nonSensitiveProfile } = profileData;

    const results = await Promise.allSettled([
      userId ? SecureStorage.set(KEYS.SECURE_USER_ID, userId) : Promise.resolve(),
      CacheStorage.set(KEYS.PROFILE_INFO, nonSensitiveProfile, -1), // Never expires
    ]);

    return results.every((r) => r.status === 'fulfilled');
  },

  async getProfile() {
    const [userId, profileData] = await Promise.all([
      SecureStorage.get(KEYS.SECURE_USER_ID),
      CacheStorage.get(KEYS.PROFILE_INFO, true),
    ]);

    if (!profileData && !userId) return null;

    return {
      userId,
      ...(profileData || {}),
    };
  },

  async updateProfile(updates) {
    const currentProfile = await this.getProfile();
    const merged = { ...(currentProfile || {}), ...updates };
    return this.saveProfile(merged);
  },

  async clearProfile() {
    await Promise.allSettled([
      SecureStorage.remove(KEYS.SECURE_USER_ID),
      CacheStorage.remove(KEYS.PROFILE_INFO),
    ]);
    return true;
  },
};

// ============================================================
// User Preferences Manager
// ============================================================
const PreferencesManager = {
  _defaults: {
    notifications: true,
    darkMode: false,
    fontSize: 'medium',
    autoPlay: true,
    dataUsage: 'normal',
    hapticFeedback: true,
  },

  async save(preferences) {
    return CacheStorage.set(KEYS.USER_PREFERENCES, preferences, -1);
  },

  async get() {
    const stored = await CacheStorage.get(KEYS.USER_PREFERENCES, true);
    return { ...this._defaults, ...(stored || {}) };
  },

  async update(updates) {
    const current = await this.get();
    const merged = { ...current, ...updates };
    return this.save(merged);
  },

  async reset() {
    return this.save({ ...this._defaults });
  },

  async getPreference(key) {
    const prefs = await this.get();
    return prefs[key] !== undefined ? prefs[key] : this._defaults[key];
  },

  async setPreference(key, value) {
    return this.update({ [key]: value });
  },
};

// ============================================================
// App Settings Manager
// ============================================================
const SettingsManager = {
  _defaults: {
    apiBaseUrl: 'https://api.example.com',
    cacheEnabled: true,
    cacheTTL: DEFAULT_CACHE_TTL,
    maxOfflineItems: 50,
    syncInterval: 15 * 60 * 1000, // 15 minutes
    debugMode: false,
    analyticsEnabled: true,
    crashReportingEnabled: true,
  },

  async save(settings) {
    return CacheStorage.set(KEYS.APP_SETTINGS, settings, -1);
  },

  async get() {
    const stored = await CacheStorage.get(KEYS.APP_SETTINGS, true);
    return { ...this._defaults, ...(stored || {}) };
  },

  async update(updates) {
    const current = await this.get();
    const merged = { ...current, ...updates };
    return this.save(merged);
  },

  async reset() {
    return this.save({ ...this._defaults });
  },

  async getSetting(key) {
    const settings = await this.get();
    return settings[key] !== undefined ? settings[key] : this._defaults[key];
  },

  async setSetting(key, value) {
    return this.update({ [key]: value });
  },
};

// ============================================================
// Session Manager
// ============================================================
const SessionManager = {
  async saveSession(sessionData) {
    // Separate sensitive session data
    const { sessionSecret, ...nonSensitiveSession } = sessionData;

    const results = await Promise.allSettled([
      sessionSecret
        ? SecureStorage.set(KEYS.SECURE_SESSION_SECRET, sessionSecret)
        : Promise.resolve(),
      CacheStorage.set(KEYS.SESSION_DATA, {
        ...nonSensitiveSession,
        lastActive: Date.now(),
      }, 7 * 24 * 60 * 60 * 1000), // 7 days TTL
    ]);

    return results.every((r) => r.status === 'fulfilled');
  },

  async getSession() {
    const [sessionSecret, sessionData] = await Promise.all([
      SecureStorage.get(KEYS.SECURE_SESSION_SECRET),
      CacheStorage.get(KEYS.SESSION_DATA),
    ]);

    if (!sessionData) return null;

    return {
      ...sessionData,
      sessionSecret,
    };
  },

  async updateLastActive() {
    const session = await CacheStorage.get(KEYS.SESSION_DATA);
    if (session) {
      session.lastActive = Date.now();
      return CacheStorage.set(KEYS.SESSION_DATA, session, 7 * 24 * 60 * 60 * 1000);
    }
    return false;
  },

  async isSessionValid() {
    const session = await CacheStorage.get(KEYS.SESSION_DATA);
    return session !== null;
  },

  async clearSession() {
    await Promise.allSettled([
      SecureStorage.remove(KEYS.SECURE_SESSION_SECRET),
      CacheStorage.remove(KEYS.SESSION_DATA),
    ]);
    return true;
  },
};

// ============================================================
// Offline Content Manager
// ============================================================
const OfflineContentManager = {
  async saveContent(contentId, content, ttl = DEFAULT_CACHE_TTL) {
    const key = `${KEYS.OFFLINE_CONTENT}/${contentId}`;
    const success = await CacheStorage.set(key, content, ttl);

    if (success) {
      await this._updateContentIndex(contentId, 'add');
    }

    return success;
  },

  async getContent(contentId) {
    const key = `${KEYS.OFFLINE_CONTENT}/${contentId}`;
    return CacheStorage.get(key);
  },

  async removeContent(contentId) {
    const key = `${KEYS.OFFLINE_CONTENT}/${contentId}`;
    const success = await CacheStorage.remove(key);

    if (success) {
      await this._updateContentIndex(contentId, 'remove');
    }

    return success;
  },

  async getAllContentIds() {
    const index = await CacheStorage.get(KEYS.OFFLINE_CONTENT, true);
    return index || [];
  },

  async getAllContent() {
    const ids = await this.getAllContentIds();
    const results = {};

    for (const id of ids) {
      const content = await this.getContent(id);
      if (content !== null) {
        results[id] = content;
      }
    }

    return results;
  },

  async saveBulkContent(contentMap, ttl = DEFAULT_CACHE_TTL) {
    const entries = Object.entries(contentMap);
    const settings = await SettingsManager.get();
    const maxItems = settings.maxOfflineItems;

    // Enforce max offline items limit
    const currentIds = await this.getAllContentIds();
    const totalAfterSave = currentIds.length + entries.length;

    if (totalAfterSave > maxItems) {
      // Remove oldest items to make room
      const toRemove = totalAfterSave - maxItems;
      const idsToRemove = currentIds.slice(0, toRemove);
      await Promise.allSettled(idsToRemove.map((id) => this.removeContent(id)));
    }

    const results = await Promise.allSettled(
      entries.map(([id, content]) => this.saveContent(id, content, ttl))
    );

    return results.every((r) => r.status === 'fulfilled' && r.value === true);
  },

  async clearAllContent() {
    const ids = await this.getAllContentIds();
    await Promise.allSettled(ids.map((id) => this.removeContent(id)));
    await CacheStorage.remove(KEYS.OFFLINE_CONTENT);
    return true;
  },

  async getContentCount() {
    const ids = await this.getAllContentIds();
    return ids.length;
  },

  async _updateContentIndex(contentId, action) {
    const index = (await CacheStorage.get(KEYS.OFFLINE_CONTENT, true)) || [];

    if (action === 'add' && !index.includes(contentId)) {
      index.push(contentId);
    } else if (action === 'remove') {
      const idx = index.indexOf(contentId);
      if (idx > -1) index.splice(idx, 1);
    }

    return CacheStorage.set(KEYS.OFFLINE_CONTENT, index, -1);
  },
};

// ============================================================
// Theme Manager
// ============================================================
const ThemeManager = {
  async saveTheme(themeSettings) {
    return CacheStorage.set(KEYS.THEME_SETTINGS, themeSettings, -1);
  },

  async getTheme() {
    return CacheStorage.get(KEYS.THEME_SETTINGS, true);
  },

  async setDarkMode(enabled) {
    const current = (await this.getTheme()) || {};
    return this.saveTheme({ ...current, darkMode: enabled });
  },

  async isDarkMode() {
    const theme = await this.getTheme();
    return theme?.darkMode || false;
  },
};

// ============================================================
// Sync Manager
// ============================================================
const SyncManager = {
  async getLastSyncTimestamp() {
    return CacheStorage.get(KEYS.LAST_SYNC_TIMESTAMP, true);
  },

  async setLastSyncTimestamp(timestamp = Date.now()) {
    return CacheStorage.set(KEYS.LAST_SYNC_TIMESTAMP, timestamp, -1);
  },

  async needsSync() {
    const lastSync = await this.getLastSyncTimestamp();
    if (!lastSync) return true;

    const settings = await SettingsManager.get();
    return Date.now() - lastSync > settings.syncInterval;
  },
};

// ============================================================
// Main LocalDataManager
// ============================================================
const LocalDataManager = {
  // Sub-managers
  tokens: TokenManager,
  profile: ProfileManager,
  preferences: PreferencesManager,
  settings: SettingsManager,
  session: SessionManager,
  offlineContent: OfflineContentManager,
  theme: ThemeManager,
  sync: SyncManager,
  secure: SecureStorage,
  cache: CacheStorage,

  // Storage keys reference
  KEYS,

  /**
   * Initialize the data manager - call on app startup
   * Preloads critical data into memory cache
   */
  async initialize() {
    try {
      // Preload frequently accessed data into memory cache
      await Promise.allSettled([
        PreferencesManager.get(),
        SettingsManager.get(),
        ThemeManager.getTheme(),
        ProfileManager.getProfile(),
      ]);

      // Update session last active
      await SessionManager.updateLastActive();

      console.log('LocalDataManager initialized successfully');
      return true;
    } catch (error) {
      console.error('LocalDataManager initialization error:', error);
      return false;
    }
  },

  /**
   * Full login flow - save all auth-related data
   */
  async onLogin({ authToken, refreshToken, userId, profile, sessionData }) {
    const results = await Promise.allSettled([
      TokenManager.saveTokens({ authToken, refreshToken }),
      ProfileManager.saveProfile({ userId, ...profile }),
      sessionData ? SessionManager.saveSession(sessionData) : Promise.resolve(),
      SyncManager.setLastSyncTimestamp(),
    ]);

    return results.every((r) => r.status === 'fulfilled');
  },

  /**
   * Full logout flow - clear all user-specific data
   */
  async onLogout() {
    const results = await Promise.allSettled([
      TokenManager.clearTokens(),
      ProfileManager.clearProfile(),
      SessionManager.clearSession(),
      OfflineContentManager.clearAllContent(),
      CacheStorage.remove(KEYS.LAST_SYNC_TIMESTAMP),
    ]);

    // Clear memory cache
    memoryCache.clear();

    return results.every((r) => r.status === 'fulfilled');
  },

  /**
   * Clear all stored data (factory reset)
   */
  async clearAll() {
    const results = await Promise.allSettled([
      SecureStorage.clearAll(),
      CacheStorage.clearAll(),
    ]);

    memoryCache.clear();

    return results.every((r) => r.status === 'fulfilled');
  },

  /**
   * Get storage diagnostics
   */
  async getDiagnostics() {
    const [
      isAuthenticated,
      sessionValid,
      offlineCount,
      lastSync,
      needsSync,
    ] = await Promise.all([
      TokenManager.isAuthenticated(),
      SessionManager.isSessionValid(),
      OfflineContentManager.getContentCount(),
      SyncManager.getLastSyncTimestamp(),
      SyncManager.needsSync(),
    ]);

    let allKeys = [];
    try {
      allKeys = await AsyncStorage.getAllKeys();
    } catch (e) {
      // ignore
    }

    return {
      isAuthenticated,
      sessionValid,
      offlineContentCount: offlineCount,
      lastSyncTimestamp: lastSync,
      needsSync,
      memoryCacheSize: memoryCache.size,
      asyncStorageKeyCount: allKeys.filter((k) => k.startsWith('@app/')).length,
      totalAsyncStorageKeys: allKeys.length,
    };
  },

  /**
   * Purge expired cache entries
   */
  async purgeExpiredCache() {
    try {
      const allKeys = await AsyncStorage.getAllKeys();
      const appKeys = allKeys.filter((k) => k.startsWith('@app/'));
      const pairs = await AsyncStorage.multiGet(appKeys);
      const keysToRemove = [];

      for (const [key, value] of pairs) {
        if (value) {
          try {
            const entry = JSON.parse(value);
            if (entry.ttl && entry.ttl !== -1 && entry.timestamp) {
              if (Date.now() - entry.timestamp > entry.ttl) {
                keysToRemove.push(key);
                memoryCache.delete(key);
              }
            }
          } catch {
            // Not a cache entry, skip
          }
        }
      }

      if (keysToRemove.length > 0) {
        await AsyncStorage.multiRemove(keysToRemove);
      }

      return keysToRemove.length;
    } catch (error) {
      console.error('purgeExpiredCache error:', error);
      return 0;
    }
  },
};

export default LocalDataManager;

export {
  TokenManager,
  ProfileManager,
  PreferencesManager,
  SettingsManager,
  SessionManager,
  OfflineContentManager,
  ThemeManager,
  SyncManager,
  SecureStorage,
  CacheStorage,
  KEYS,
};